#!/usr/bin/env node
/**
 * check-version-consistency.mjs
 *
 * Asserts that the application version is consistent across all
 * version-bearing files in the repository. Fails the build (exit 1)
 * if root and desktop package versions disagree, or if the desktop
 * version disagrees with what `app.getVersion()` would resolve to
 * (i.e. the published value).
 *
 * This is a defensive guard for the updater:
 *  - The installer filename is built from `apps/desktop/package.json`
 *  - `latest.yml` is generated by electron-builder from the same
 *  - `app.getVersion()` reads the desktop package.json at runtime
 *  - The renderer displays `status.currentVersion` (i.e. app.getVersion)
 *
 * If any of these drift, the updater may publish a 0.2.0 release but
 * display "0.1.0" (or vice versa), which is exactly the bug this fix
 * was designed to eliminate.
 *
 * Usage:
 *   node scripts/check-version-consistency.mjs
 *
 * Exit codes:
 *   0 — all versions agree
 *   1 — divergence detected
 */

import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
// Allow callers to override the repository root via env var
// (useful for tests and CI sandboxes).
const ROOT = process.env.SCREENLINK_ROOT
  ? path.resolve(process.env.SCREENLINK_ROOT)
  : path.resolve(__dirname, "..");

const SEMVER_RE = /^(0|[1-9]\d*)\.(0|[1-9]\d*)\.(0|[1-9]\d*)$/;

function readJson(filePath) {
  const text = fs.readFileSync(filePath, "utf-8");
  return JSON.parse(text);
}

function main() {
  const rootPkgPath = path.join(ROOT, "package.json");
  const desktopPkgPath = path.join(ROOT, "apps", "desktop", "package.json");

  const rootPkg = readJson(rootPkgPath);
  const desktopPkg = readJson(desktopPkgPath);

  const errors = [];

  if (typeof rootPkg.version !== "string" || !SEMVER_RE.test(rootPkg.version)) {
    errors.push(`Root package.json has invalid or missing version: ${rootPkg.version}`);
  }
  if (typeof desktopPkg.version !== "string" || !SEMVER_RE.test(desktopPkg.version)) {
    errors.push(`Desktop package.json has invalid or missing version: ${desktopPkg.version}`);
  }

  if (rootPkg.version !== desktopPkg.version) {
    errors.push(
      `Root package version (${rootPkg.version}) does not match desktop package version (${desktopPkg.version}).`,
    );
  }

  if (errors.length > 0) {
    console.error("[check-version-consistency] FAIL");
    for (const err of errors) {
      console.error("  -", err);
    }
    process.exit(1);
  }

  console.log(
    `[check-version-consistency] OK — root and desktop both report version ${rootPkg.version}`,
  );
  process.exit(0);
}

main();
